-- Update monthlyRevenue for the 4 new services from their billing items
UPDATE services SET monthlyRevenue = 399.00 WHERE externalId = 'S7428';
UPDATE services SET monthlyRevenue = 200.91 WHERE externalId = 'S7429';
UPDATE services SET monthlyRevenue = 142.30 WHERE externalId = 'S7430';
UPDATE services SET monthlyRevenue = 164.27 WHERE externalId = 'S7431';

-- Final summary of billing items
SELECT matchStatus, COUNT(*) as count, SUM(lineAmount) as total
FROM billing_items
GROUP BY matchStatus
ORDER BY matchStatus;

